        if parent[x] != x:
            parent[x] = find(parent[x])
        return parent[x]

    for u, v in connections:
        ru = find(u)
        rv = find(v)
        if ru != rv:
            parent[rv] = ru

    for i in range(1, c + 1):
        find(i)

    off_time = [10**15] * (c + 1)
    num_queries = len(queries)
    for i in range(num_queries):
        if queries[i][0] == 2:
            x = queries[i][1]
            if off_time[x] > i:
                off_time[x] = i

    comp_heaps = {}
    for node in range(1, c + 1):
        if off_time[node] > num_queries - 1:
            r = find(node)
            if r not in comp_heaps:
                comp_heaps[r] = []
            heapq.heappush(comp_heaps[r], node)

    ans_list = []
    for idx in range(num_queries - 1, -1, -1):
        q = queries[idx]
        if q[0] == 1:
            x = q[1]
            r = find(x)
            if off_time[x] > idx:
                ans_list.append(x)
            else:
                if r not in comp_heaps:
                    comp_heaps[r] = []
                heap = comp_heaps[r]
                while heap and off_time[heap[0]] <= idx:
                    heapq.heappop(heap)
                if heap:
                    ans_list.append(heap[0])
                else:
                    ans_list.append(-1)
        else:
            x = q[1]
            r = find(x)
            if r not in comp_heaps:
                comp_heaps[r] = []
            heapq.heappush(comp_heaps[r], x)

    ans_list.reverse()
    return ans_list
